import datetime
import functools
from flask import Flask, request, jsonify, abort
import jwt

app = Flask(__name__)
app.config["SECRET_KEY"] = "your_secret_key"  # Change this to a secure secret in production

# Dummy user for demonstration
USER_DATA = {
    "username": "testuser",
    "password": "testpass"
}

def generate_token(username):
    payload = {
        "sub": username,
        "iat": datetime.datetime.utcnow(),
        "exp": datetime.datetime.utcnow() + datetime.timedelta(minutes=30)
    }
    token = jwt.encode(payload, app.config["SECRET_KEY"], algorithm="HS256")
    return token

def token_required(f):
    @functools.wraps(f)
    def decorated(*args, **kwargs):
        token = None
        if "Authorization" in request.headers:
            parts = request.headers["Authorization"].split()
            if parts[0].lower() == "bearer" and len(parts) == 2:
                token = parts[1]
        if not token:
            return jsonify({"message": "Token is missing!"}), 401
        try:
            data = jwt.decode(token, app.config["SECRET_KEY"], algorithms=["HS256"])
            current_user = data["sub"]
        except jwt.ExpiredSignatureError:
            return jsonify({"message": "Token has expired!"}), 401
        except jwt.InvalidTokenError:
            return jsonify({"message": "Invalid token!"}), 401
        return f(current_user, *args, **kwargs)
    return decorated

@app.route("/login", methods=["POST"])
def login():
    auth = request.get_json()
    if not auth or not auth.get("username") or not auth.get("password"):
        return jsonify({"message": "Username and password required"}), 400

    username = auth.get("username")
    password = auth.get("password")

    if username != USER_DATA["username"] or password != USER_DATA["password"]:
        return jsonify({"message": "Invalid credentials"}), 401

    token = generate_token(username)
    return jsonify({"token": token})

@app.route("/protected", methods=["GET"])
@token_required
def protected(current_user):
    return jsonify({"message": f"Welcome {current_user}, you have accessed a protected route."})

if __name__ == "__main__":
    app.run(debug=True)